<style>body{margin:0;font-family:Inter,sans-serif;background:#171532;color:#fff;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:1rem;background-image:linear-gradient(rgba(255,255,255,.05) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.05) 1px,transparent 1px);background-size:48px 48px}.b{font-family:'JetBrains Mono',monospace;font-size:7rem;font-weight:600;line-height:1;background:linear-gradient(135deg,#8585DF,#FF8A3D);-webkit-background-clip:text;background-clip:text;color:transparent}.btn{display:inline-flex;align-items:center;gap:.4rem;font-weight:600;border-radius:.75rem;text-decoration:none;padding:.8rem 1.5rem;font-size:.95rem}.p{background:#5B5BD6;color:#fff}.w{background:rgba(255,255,255,.1);color:#fff;border:1px solid rgba(255,255,255,.2)}</style></head>
<body><div style="text-align:center;max-width:30rem">
  <div class="b">404</div>
  <h1 style="font-family:'Space Grotesk',sans-serif;font-size:1.5rem;margin:1rem 0 .5rem">Room not found</h1>
  <p style="color:rgba(255,255,255,.55);font-size:.9rem;margin-bottom:2rem">The page you're looking for doesn't exist or may have moved.</p>
  <div style="display:flex;gap:.75rem;justify-content:center;flex-wrap:wrap"><a href="/" class="btn p">Back to home</a><a href="/search" class="btn w">Search hotels</a></div>
